import{_ as d,o as e,c as a,a4 as r}from"./chunks/framework.BybBnFXO.js";const c=JSON.parse('{"title":"氧化物","description":"","frontmatter":{"title":"氧化物","mineralGroup":"oxides"},"headers":[],"relativePath":"zh/mineral-groups/oxides.md","filePath":"zh/mineral-groups/oxides.md","lastUpdated":1784176423000}'),i={name:"zh/mineral-groups/oxides.md"};function o(l,t,h,n,s,p){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="氧化物" tabindex="-1">氧化物 <a class="header-anchor" href="#氧化物" aria-label="Permalink to &quot;氧化物&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>氧化物类是宝石学最重要类之一，涵盖刚玉族（红宝石、蓝宝石）、 尖晶石族、金红石族、水铝矿等。致色元素以过渡金属为主 （Cr、Fe、Ti、V）。因晶格中化学键强（离子键 + 部分共价性）， 氧化物硬度普遍较高（Mohs 7–9），是良好的耐久性宝石。</p><h2 id="化学式类型" tabindex="-1">化学式类型 <a class="header-anchor" href="#化学式类型" aria-label="Permalink to &quot;化学式类型&quot;">​</a></h2><p>M₂O₃ / MO₂ / MO</p><h2 id="结构" tabindex="-1">结构 <a class="header-anchor" href="#结构" aria-label="Permalink to &quot;结构&quot;">​</a></h2><p>氧离子（O²⁻）构成六方最密堆积或立方最密堆积骨架，金属阳离子 填充八面体或四面体间隙位置。刚玉族为三方晶系，尖晶石族为等轴 晶系。</p><h2 id="代表性宝石" tabindex="-1">代表性宝石 <a class="header-anchor" href="#代表性宝石" aria-label="Permalink to &quot;代表性宝石&quot;">​</a></h2><table tabindex="0"><thead><tr><th>宝石</th><th>化学式</th><th>亚族</th></tr></thead><tbody><tr><td>Ruby / 红宝石</td><td>Al₂O₃ + Cr</td><td>corundum</td></tr><tr><td>Sapphire (blue) / 蓝宝石</td><td>Al₂O₃ + Fe,Ti</td><td>corundum</td></tr><tr><td>Yellow Sapphire / 黄宝石</td><td>Al₂O₃ + Fe</td><td>corundum</td></tr><tr><td>Padparadscha / 帕帕拉恰</td><td>Al₂O₃ + Cr,Fe</td><td>corundum</td></tr><tr><td>Spinel / 尖晶石</td><td>MgAl₂O₄</td><td>spinel</td></tr><tr><td>Hematite / 赤铁矿</td><td>Fe₂O₃</td><td>hematite</td></tr><tr><td>Rutile / 金红石</td><td>TiO₂</td><td>rutile</td></tr><tr><td>Diaspore / 水铝石</td><td>AlO(OH)</td><td>boehmite</td></tr><tr><td>Cassiterite / 锡石</td><td>SnO₂</td><td>rutile</td></tr><tr><td>Spinel (cobalt-blue) / 钴蓝尖晶石</td><td>CoAl₂O₄</td><td>spinel</td></tr></tbody></table><p><em>详见<a href="./intro.html">矿物组总览</a>。</em></p>',10)])])}const m=d(i,[["render",o]]);export{c as __pageData,m as default};
